from odoo import models, api

from .quick_links_config import quick_links_icp_get_enabled


class IrUiMenu(models.Model):
    _inherit = 'ir.ui.menu'

    @api.model_create_multi
    def create(self, vals_list):
        """
        When a new main menu is created, trigger reordering to maintain priority order.
        """
        menus = super(IrUiMenu, self).create(vals_list)

        # Reorder once if any created menu is a top-level app menu.
        if self.env.context.get('reorder_on_create', True) and any(
            not menu.parent_id for menu in menus
        ):
            self.env['main.menu.priority'].sudo().action_reorder_main_menus()

        return menus

    @api.model
    def get_quick_links_payload(self):
        """
        Frontend-safe endpoint for app switcher grouping.
        Uses sudo internally and always returns a fallback payload.
        """
        enabled = quick_links_icp_get_enabled(self.env)
        if not enabled:
            return {"enabled": False, "menu_ids": []}

        if "main.menu.priority" not in self.env:
            return {"enabled": False, "menu_ids": []}

        priorities = self.env["main.menu.priority"].sudo().search(
            [("active", "=", True)],
            order="sequence, id",
        )
        return {"enabled": True, "menu_ids": priorities.mapped("menu_id").ids}

