class ProjectNotes(models.Model):
    _name = 'project.notes'
    _description = 'Project Notes'
    _order = 'note_taken_date desc, id desc'

    sequence = fields.Integer(string='#', compute='_compute_sequence', store=False)
    note_taken_date = fields.Date(
        string="Date",
        default=fields.Date.context_today
    )

    notes = fields.Html(string="Notes", sanitize=True, strip_classes=True)
    note_taken_by = fields.Many2one(
        'res.partner',
        string="Note Taker",
        default=lambda self: self.env.user.partner_id
    )

    project_id = fields.Many2one('project.project', string="Project", required=True)

    @api.depends('project_id')
    def _compute_sequence(self):
        """Compute row number based on current order within the project"""
        for record in self:
            if record.project_id:
                # Get all notes for this project in the default order
                notes = self.search([
                    ('project_id', '=', record.project_id.id)
                ], order='note_taken_date desc, id desc')
                # Find the position of current record (1-based)
                record.sequence = notes.ids.index(record.id) + 1 if record.id in notes.ids else 0
            else:
                record.sequence = 0

