@api.depends('project_id')
def _compute_sequence(self):
    """Compute row number from bottom to top (oldest = 1, newest = highest)"""
    for record in self:
        if record.project_id:
            # Get all notes for this project in the default order (newest first)
            notes = self.search([
                ('project_id', '=', record.project_id.id)
            ], order='note_taken_date desc, id desc')
            # Reverse numbering: bottom to top
            if record.id in notes.ids:
                position = notes.ids.index(record.id)
                record.sequence = len(notes) - position
            else:
                record.sequence = 0
        else:
            record.sequence = 0

