/* ========================================================================
   Global Style - Compact List Views
   ======================================================================== */

/* ========================================================================
   List View Padding & Spacing
   ======================================================================== */

/* Reduce padding in all list view cells (table data and headers) */
.o_list_table td,
.o_list_table th {
    padding: 2px 4px !important;
    vertical-align: middle;
}

/* Reduce font size for more compact appearance */
.o_list_table {
    font-size: 13px;
}

/* Reduce row height */
.o_list_table tbody tr {
    height: 28px;
}

/* ========================================================================
   List View Headers
   ======================================================================== */

/* Compact header cells */
.o_list_table thead th {
    padding: 4px 4px !important;
    font-size: 12px;
    font-weight: 600;
}

/* ========================================================================
   Form View Embedded Lists (One2many, Many2many)
   ======================================================================== */

/* Compact padding for embedded list views in forms */
.o_field_widget.o_field_one2many .o_list_table td,
.o_field_widget.o_field_one2many .o_list_table th,
.o_field_widget.o_field_many2many .o_list_table td,
.o_field_widget.o_field_many2many .o_list_table th {
    padding: 2px 4px !important;
}

/* ========================================================================
   Optional: Buttons in List Views
   ======================================================================== */

/* Make action buttons more compact */
.o_list_table .o_list_button {
    padding: 2px 6px !important;
    font-size: 12px;
}

/* ========================================================================
   Optional: Status Badges
   ======================================================================== */

/* Compact badges/tags in list views */
.o_list_table .badge {
    padding: 2px 6px;
    font-size: 11px;
}

/* ========================================================================
   Optional: Checkbox and Selection Fields
   ======================================================================== */

/* Center checkboxes with reduced padding */
.o_list_table .o_list_record_selector {
    padding: 0 !important;
    text-align: center;
}

/* ========================================================================
   CUSTOMIZATION NOTES
   ========================================================================

   You can adjust these values to your preference:

   Padding Options:
   - Extra Compact: 1px 3px
   - Compact (current): 2px 4px
   - Comfortable: 4px 6px
   - Default Odoo: 6px 8px
   - Spacious: 8px 12px

   Font Size Options:
   - Extra Small: 11px
   - Small (current): 13px
   - Default: 14px
   - Large: 15px

   Row Height Options:
   - Extra Compact: 24px
   - Compact (current): 28px
   - Comfortable: 32px
   - Default: 36px
   - Spacious: 40px

   ======================================================================== */

