input.content:
/* Scope of Work field - Collapsible Display */

.o_scope_of_work_wrapper {
    position: relative;
}

/* Limit initial height to approximately 5 lines */
.o_scope_of_work_wrapper .o_scope_of_work_field {
    max-height: 150px;
    overflow: hidden;
    position: relative;
    transition: max-height 0.3s ease;
}

/* Expanded state */
.o_scope_of_work_wrapper.expanded .o_scope_of_work_field {
    max-height: none;
}

/* Fade effect at bottom when collapsed */
.o_scope_of_work_wrapper .o_scope_of_work_field::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 40px;
    background: linear-gradient(to bottom, transparent, white);
    pointer-events: none;
}

/* Hide fade when expanded */
.o_scope_of_work_wrapper.expanded .o_scope_of_work_field::after {
    display: none;
}

/* Show More/Less button */
.o_scope_of_work_wrapper::after {
    content: 'Show More ▼';
    display: block;
    color: #007bff;
    cursor: pointer;
    font-size: 13px;
    margin-top: 8px;
    text-align: left;
}

.o_scope_of_work_wrapper:hover::after {
    text-decoration: underline;
}

.o_scope_of_work_wrapper.expanded::after {
    content: 'Show Less ▲';
}

/* Click handler area */
.o_scope_of_work_wrapper {
    cursor: pointer;
}

