# -*- coding: utf-8 -*-
"""Log form opens (web client) as internal notes on mail.thread records."""
from __future__ import annotations

import time
from datetime import datetime, timezone
from functools import partial
from zoneinfo import ZoneInfo

from babel.dates import format_datetime

import odoo
from odoo import _, api, models

_DENVER_TZ = ZoneInfo("America/Denver")

# (model name, record id, user id) -> monotonic time of last chatter post
_OPEN_LOG_TS: dict[tuple[str, int, int], float] = {}
_THROTTLE_SECONDS = 75.0


def _denver_open_time_display() -> str:
    dt = datetime.now(timezone.utc).astimezone(_DENVER_TZ)
    return format_datetime(dt, "MM/dd/yyyy h:mm:ss a", locale="en_US")


def _open_log_throttle_allow(model_name: str, res_id: int, uid: int) -> bool:
    key = (model_name, res_id, uid)
    now = time.monotonic()
    prev = _OPEN_LOG_TS.get(key)
    if prev is not None and (now - prev) < _THROTTLE_SECONDS:
        return False
    _OPEN_LOG_TS[key] = now
    if len(_OPEN_LOG_TS) > 8000:
        cutoff = now - _THROTTLE_SECONDS * 2
        for k, ts in list(_OPEN_LOG_TS.items()):
            if ts < cutoff:
                del _OPEN_LOG_TS[k]
    return True


def _chatter_open_log_postcommit_run(dbname, uid, context, payloads):
    """Post chatter lines after the readonly web_read RPC commits (own cursor)."""
    if not payloads:
        return
    with odoo.registry(dbname).cursor() as cr:
        env = api.Environment(cr, uid, context)
        for pl in payloads:
            rec = env[pl["model"]].browse(pl["res_id"])
            if not rec.exists():
                continue
            rec.message_post(
                body=pl["body"],
                message_type="notification",
                subtype_xmlid="mail.mt_note",
            )


def schedule_chatter_open_logs_after_web_read(records, specification, result):
    """Shared hook after ``super().web_read()`` (also used by ``crm.lead`` without mixin _inherit)."""
    specs = specification or {}
    if not specs or set(specs.keys()) <= {"id"}:
        return
    if not result or records.env.user.share:
        return
    payloads = []
    user_name = records.env.user.display_name
    for rec in records:
        if not rec.id:
            continue
        label = rec._chatter_open_log_pipeline_label()
        if not label:
            continue
        if not _open_log_throttle_allow(rec._name, rec.id, records.env.uid):
            continue
        when = _denver_open_time_display()
        body = _(
            "%(label)s: record opened by %(user)s at %(when)s (Mountain Time, America/Denver, 12-hour clock)."
        ) % {
            "label": label,
            "user": user_name,
            "when": when,
        }
        payloads.append({"model": rec._name, "res_id": rec.id, "body": body})
    if payloads:
        records.env.cr.postcommit.add(
            partial(
                _chatter_open_log_postcommit_run,
                records.env.cr.dbname,
                records.env.uid,
                dict(records.env.context or {}),
                payloads,
            )
        )


class ChatterOpenLogMixin(models.AbstractModel):
    _name = "bd_sourcesought.chatter_open_log.mixin"
    _description = "Chatter note when an internal user opens a record in the web form (web_read)."

    @api.readonly
    def web_read(self, specification: dict[str, dict]) -> list[dict]:
        result = super().web_read(specification)
        schedule_chatter_open_logs_after_web_read(self, specification, result)
        return result

    def _chatter_open_log_pipeline_label(self):
        """Return a short pipeline name for the chatter line, or False to skip."""
        self.ensure_one()
        return False

