        try {
            if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
                alert('Camera access is not available. Please use HTTPS or localhost, or use the Upload Photos option instead.');
                return;
            }

            console.log('[DailyForm] Requesting camera access...');
            stream = await navigator.mediaDevices.getUserMedia({
                video: {
                    facingMode: { ideal: 'environment' },
                    width: { ideal: 1920 },
                    height: { ideal: 1080 }
                }
            });

            console.log('[DailyForm] Camera access granted!');
            camera.srcObject = stream;
            showModal(cameraModalEl);

