from odoo import models, fields, api


class ResConfigSettings(models.TransientModel):
    _inherit = 'res.config.settings'

    daily_scheduling_user_id = fields.Many2one(
        'res.users',
        string='Daily Report Scheduling User',
        help='User to assign scheduling tasks (Elena or Alejandra). '
             'This user will receive "Create Timesheet" and "Upload Timesheet" activities.',
        config_parameter='project_dailys.scheduling_user'
    )

    @api.model
    def get_values(self):
        res = super().get_values()
        user_id = self.env['ir.config_parameter'].sudo().get_param(
            'project_dailys.scheduling_user', False
        )
        if user_id:
            res['daily_scheduling_user_id'] = int(user_id)
        return res

    def set_values(self):
        super().set_values()
        self.env['ir.config_parameter'].sudo().set_param(
            'project_dailys.scheduling_user',
            self.daily_scheduling_user_id.id if self.daily_scheduling_user_id else False
        )

